export interface GenerationSettings {
  medium: string;
  genre: string;
  lighting: string;
  colorGrading: string;
  aspectRatio: string;
  customPrompt: string;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR',
}

export type AspectRatio = "1:1" | "3:4" | "4:3" | "9:16" | "16:9";

import { GoogleGenAI } from "@google/genai";
import { AspectRatio } from "../types";

// Initialize Gemini Client
// IMPORTANT: Using the specific Nano Banana model requested: gemini-2.5-flash-image
const MODEL_NAME = 'gemini-2.5-flash-image';

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API Key not found in environment variables");
    }
    aiClient = new GoogleGenAI({ apiKey });
  }
  return aiClient;
};

export const generateMockup = async (
  imageBase64: string,
  prompt: string,
  aspectRatio: AspectRatio
): Promise<string> => {
  const client = getClient();

  // Strip prefix if present (e.g., "data:image/png;base64,")
  const base64Data = imageBase64.split(',')[1] || imageBase64;

  // Detect mime type roughly (defaulting to png if unknown, though usually handled by split)
  const mimeType = imageBase64.match(/[^:]\w+\/[\w-+\d.]+(?=;|,)/)?.[0] || 'image/png';

  try {
    const response = await client.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
          // imageSize is NOT supported by gemini-2.5-flash-image, only Pro.
        },
      },
    });

    // Parse response for image
    // The model might return text if it refuses, or multiple parts.
    // We look for inlineData.
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }

    throw new Error("No image generated. The model might have refused the request or returned only text.");

  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

import React, { useCallback, useState } from 'react';

interface ImageDropzoneProps {
  onImageSelect: (base64: string) => void;
  selectedImage: string | null;
}

const ImageDropzone: React.FC<ImageDropzoneProps> = ({ onImageSelect, selectedImage }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  }, []);

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      if (event.target?.result) {
        onImageSelect(event.target.result as string);
      }
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="w-full mb-6">
      <label className="block text-sm font-medium text-slate-400 mb-2">
        Source Image (Product or Logo)
      </label>

      <div
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={`relative w-full h-48 border-2 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all duration-200 overflow-hidden group ${
          isDragging
            ? 'border-indigo-500 bg-indigo-500/10'
            : 'border-slate-600 hover:border-slate-500 hover:bg-slate-800'
        }`}
      >
        <input
          type="file"
          accept="image/*"
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
          onChange={handleFileInput}
        />

        {selectedImage ? (
          <div className="relative w-full h-full flex items-center justify-center bg-slate-900">
            <img 
              src={selectedImage} 
              alt="Source" 
              className="max-w-full max-h-full object-contain p-2" 
            />
            <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
              <span className="text-white text-sm font-medium">Click or Drop to Replace</span>
            </div>
          </div>
        ) : (
          <div className="text-center p-4">
            <div className="w-12 h-12 rounded-full bg-slate-700 flex items-center justify-center mx-auto mb-3 text-slate-300">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 0 1 5.25 21h13.5A2.25 2.25 0 0 1 21 18.75V16.5m-13.5-9L12 3m0 0 4.5 4.5M12 3v13.5" />
              </svg>
            </div>
            <p className="text-sm font-medium text-slate-300">
              Click to upload or drag and drop
            </p>
            <p className="text-xs text-slate-500 mt-1">
              PNG, JPG, WEBP up to 5MB
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageDropzone;

